#[test]
fn lvlrestart_zero_and_default_coexist_full_three_level_worked_example() {
    // Three-level abstractNum: ilvl 1 omits lvlRestart (resets after top level),
    // ilvl 2 has lvlRestart=0 (never restarts). This is the spec's worked example.
    let numbering = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="0"><w:lvl w:ilvl="0"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlText w:val="%1)"/><w:lvlJc w:val="start"/></w:lvl><w:lvl w:ilvl="1"><w:start w:val="1"/><w:numFmt w:val="lowerLetter"/><w:lvlText w:val="%2)"/><w:lvlJc w:val="start"/></w:lvl><w:lvl w:ilvl="2"><w:start w:val="1"/><w:numFmt w:val="lowerRoman"/><w:lvlRestart w:val="0"/><w:lvlText w:val="%3)"/><w:lvlJc w:val="start"/></w:lvl></w:abstractNum><w:num w:numId="9"><w:abstractNumId w:val="0"/></w:num></w:numbering>"#;
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="9"/></w:numPr></w:pPr><w:r><w:t>L1a</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="1"/><w:numId w:val="9"/></w:numPr></w:pPr><w:r><w:t>L2a</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="2"/><w:numId w:val="9"/></w:numPr></w:pPr><w:r><w:t>L3a</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="2"/><w:numId w:val="9"/></w:numPr></w:pPr><w:r><w:t>L3b</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="9"/></w:numPr></w:pPr><w:r><w:t>L1b</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="1"/><w:numId w:val="9"/></w:numPr></w:pPr><w:r><w:t>L2b</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="2"/><w:numId w:val="9"/></w:numPr></w:pPr><w:r><w:t>L3c</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/numbering.xml", numbering)]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.9.10: omitted lvlRestart on ilvl 1 + lvlRestart=0 on ilvl 2 is schema-valid; Word opens without repair",
    );
    assert_eq!(
        accepted_text(&b).trim(),
        "L1a\n\nL2a\n\nL3a\n\nL3b\n\nL1b\n\nL2b\n\nL3c".trim(),
        "to_text() carries run text only; accept-all reproduces the seven run strings verbatim, proving the mixed lvlRestart resolution does not corrupt body text (ISO 29500-1 §17.9.10)"
    );
}

#[test]
fn lvlrestart_one_resets_only_on_top_level_not_middle() {
    let numbering = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="5"><w:lvl w:ilvl="0"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlText w:val="%1."/></w:lvl><w:lvl w:ilvl="1"><w:start w:val="1"/><w:numFmt w:val="lowerLetter"/><w:lvlText w:val="%2)"/></w:lvl><w:lvl w:ilvl="2"><w:start w:val="1"/><w:numFmt w:val="lowerRoman"/><w:lvlRestart w:val="1"/><w:lvlText w:val="%3)"/></w:lvl></w:abstractNum><w:num w:numId="7"><w:abstractNumId w:val="5"/></w:num></w:numbering>"#;
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="2"/><w:numId w:val="7"/></w:numPr></w:pPr><w:r><w:t>D1</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="1"/><w:numId w:val="7"/></w:numPr></w:pPr><w:r><w:t>Mid</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="2"/><w:numId w:val="7"/></w:numPr></w:pPr><w:r><w:t>D2</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/numbering.xml", numbering)]);

    assert_eq!(
        accepted_text(&b).trim(),
        "D1\n\nMid\n\nD2".trim(),
        "Sanity: accept-all run text is body text only; the three runs reproduce unchanged, proving the override numbering does not corrupt body text (ISO 29500-1 §17.9.10; MS-OI29500 §2.1.282)"
    );
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.9.10: lvlRestart=1 is schema-valid (within Word's 0..=7 band); Word opens without repair",
    );
}

