#[test]
fn lvlrestart_higher_than_current_level_ignored_open_clean() {
    let numbering = "<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"yes\"?>\n<w:numbering xmlns:w=\"http://schemas.openxmlformats.org/wordprocessingml/2006/main\"><w:abstractNum w:abstractNumId=\"4\"><w:lvl w:ilvl=\"0\"><w:start w:val=\"1\"/><w:numFmt w:val=\"decimal\"/><w:lvlRestart w:val=\"3\"/><w:lvlText w:val=\"%1.\"/><w:lvlJc w:val=\"start\"/></w:lvl></w:abstractNum><w:num w:numId=\"6\"><w:abstractNumId w:val=\"4\"/></w:num></w:numbering>";
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="6"/></w:numPr></w:pPr><w:r><w:t>Higher restart ignored</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/numbering.xml", numbering)]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.9.10 makes a higher-than-current lvlRestart an ignored no-op (not invalid); value 3 is inside Word's 0..=7 band (MS-OI29500 §2.1.282) and CT_DecimalNumber-valid; Word opens without repair",
    );
    assert_eq!(
        accepted_text(&b).trim(),
        "Higher restart ignored".trim(),
        "lvlRestart only affects the synthesized marker counter and here is ignored entirely; accept-all reproduces only the paragraph's run content (ISO 29500-1 §17.9.10)"
    );
}

#[ignore = "open question: spec expected value concatenates the six runs with no separators (\"L0aL1aL2aL2bL1bL2c\"), but to_text() joins blocks by a blank line; opens-clean passes — likely a test-bug, not a Word gap"]
#[test]
fn lvl_restart_n_gt_1_restart_band_opens_clean() {
    let numbering = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="0"><w:lvl w:ilvl="0"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlText w:val="%1."/><w:lvlJc w:val="start"/></w:lvl><w:lvl w:ilvl="1"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlText w:val="%1.%2."/><w:lvlJc w:val="start"/></w:lvl><w:lvl w:ilvl="2"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlRestart w:val="2"/><w:lvlText w:val="%1.%2.%3."/><w:lvlJc w:val="start"/></w:lvl></w:abstractNum><w:num w:numId="1"><w:abstractNumId w:val="0"/></w:num></w:numbering>"#;
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>L0a</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="1"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>L1a</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="2"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>L2a</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="2"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>L2b</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="1"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>L1b</w:t></w:r></w:p><w:p><w:pPr><w:numPr><w:ilvl w:val="2"/><w:numId w:val="1"/></w:numPr></w:pPr><w:r><w:t>L2c</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/numbering.xml", numbering)]);

    assert_opens_clean(
        &b,
        "lvlRestart=2 is inside Word's permitted 0..=7 band (MS-OI29500 §2.1.282) and CT_DecimalNumber-valid (ISO 29500-1 §17.9.1); Word opens without repair",
    );
    assert_eq!(
        accepted_text(&b).trim(),
        "L0aL1aL2aL2bL1bL2c".trim(),
        "Numbering markers are layout metadata (ISO 29500-1 §17.9.10), not run text; accept-all reproduces only the authored body runs unchanged regardless of restart semantics"
    );
}
